import type { DeviceOS } from '../../../types';

import { getReq } from '@meli/server-context';

import {
  KNOWN_OS,
  OS_PLATFORM_NAME_HEADER,
  OS_PLATFORM_VERSION_HEADER,
} from '../constants';

export function getDeviceOS(): DeviceOS | undefined {
  const { device, headers } = getReq();
  const { osName, osVersion } = device;

  if (osName) {
    return { name: osName, version: osVersion };
  }

  const name = headers[OS_PLATFORM_NAME_HEADER];
  const version = headers[OS_PLATFORM_VERSION_HEADER] as string | undefined;

  if (typeof name !== 'string' || !KNOWN_OS.has(name)) {
    return undefined;
  }

  return { name: name.toLowerCase(), version };
}
